const ENUM_LABELS: Record<string, string> = {
  IntroType: '入场动画',
  OutroType: '出场动画',
  GroupAnimationType: '组合动画',
  TransitionType: '转场',
  VideoSceneEffectType: '画面特效',
  VideoCharacterEffectType: '人物特效',
  FilterType: '滤镜',
  MaskType: '蒙版',
  MixModeType: '混合模式',
  AudioSceneEffectType: '音频场景特效',
  ToneEffectType: '音色效果',
  SpeechToSongType: '声音成曲',
  TextIntro: '文字入场动画',
  TextOutro: '文字出场动画',
  TextLoopAnim: '文字循环动画',
  FontType: '字体',
  TrackType: '轨道类型',
  KeyframeProperty: '关键帧属性（全量，视频专用属性含）',
  KeyframePropertyVisual: '关键帧属性（位置/旋转/缩放，文字/贴纸适用）',
  ExportResolution: '分辨率',
  ExportFramerate: '帧率',
  ShrinkMode: '缩短模式',
  ExtendMode: '延长模式',
}

function resolveEnums(keys: string[]): EnumTypeData[] {
  return keys.map((key) => ({
    key,
    label: ENUM_LABELS[key] ?? key,
    values: ENUM_VALUES[key] ?? [],
  }))
}

